import './Main.css'
import POST from '../Post/Post'

import React, { Component } from 'react'

export default class Main extends Component {

    openWindPots = (id, bool) => {
        this.props.openWindPots(id, bool)
    }

    render() {
        const { list, tag } = this.props
        let array = []
        if (this.props.listVisible.length === 0) {
            for (let i = 0; i < this.props.list.length; i++) {
                array.push(<POST key={this.props.list[i].id} openWindPots={this.openWindPots} list={this.props.list[i]} />)
            }
        } else if (this.props.tag !== null) {
            // for (let i = 0; i < this.props.list.length; i++) {
            // if (this.props.list[i].tags.indexOf(this.props.tag.split(",")[]) !== -1) {
            //     array.push(
            //         <POST key={this.props.list[i].id} openWindPots={this.openWindPots} list={this.props.list[i]} />
            //     )
            // }
            // }

            function params(index, i) {
                return list[i].tags.indexOf(tag.split(",")[index]) !== -1
            }
            for (let i = 0; i < this.props.list.length; i++) {
                if (params(0, i) || params(1, i) || params(2, i) || params(3, i)) {
                    array.push(
                        <POST key={this.props.list[i].id} openWindPots={this.openWindPots} list={this.props.list[i]} />
                    )
                }
            }
        } else {
            for (let i = 0; i < this.props.list.length; i++) {
                if (this.props.list[i].tags.indexOf(this.props.listVisible.toLowerCase()) !== -1) {
                    array.push(<POST key={this.props.list[i].id} openWindPots={this.openWindPots} list={this.props.list[i]} />)
                }
            }
        }

        return (
            <div className="main-block">
                {array}
                {/* Tag: {this.props.tag.split(",")} <br />
                TagCount: {this.props.tag.split(",").length} <br />
                ListApp: {this.props.list[0].tags} <br />
                ListAppCount: {this.props.list[0].tags.split(",").length} */}
            </div>
        )
    }
}
